import { hasPermissionCode } from '../utils/erpPermissionCode';

const PREFIX = 'erp-supply:purchasing:orders';

export function useDdmhPermissions() {
  const canWrite = hasPermissionCode(`${PREFIX}:write`);
  return {
    canRead: hasPermissionCode(`${PREFIX}:read`),
    canWrite,
    canCreate: canWrite,
    canConfirm: hasPermissionCode(`${PREFIX}:confirm`) || canWrite,
    canClose: hasPermissionCode(`${PREFIX}:close`) || canWrite,
  };
}
