import { buildVoucherListToolbarActions } from '@linm-soft-org/linm-web-common-components';
import type { LinListToolbarActionDef } from '@linm-soft-org/linm-web-common-components';

export type PurchasingListToolbarParams = {
  testIdPrefix: string;
  onRefresh: () => void;
  onEditConfig?: () => void;
  canCreate?: boolean;
  onCreate?: () => void;
  canView?: boolean;
  onView?: () => void;
  canEdit?: boolean;
  onEdit?: () => void;
  canApprove?: boolean;
  onApprove?: () => void;
  approveLabel?: string;
};

export function buildPurchasingListToolbar(p: PurchasingListToolbarParams): LinListToolbarActionDef[] {
  const actions = buildVoucherListToolbarActions({
    testIdPrefix: p.testIdPrefix,
    onRefresh: p.onRefresh,
    onEditConfig: p.onEditConfig,
    canCreate: p.canCreate,
    onCreate: p.onCreate,
    canView: p.canView,
    onView: p.onView,
    canEdit: p.canEdit,
    onEdit: p.onEdit,
    canApprove: p.canApprove,
    onApprove: p.onApprove,
    approveDisabled: !p.canApprove,
  });
  if (!p.approveLabel) return actions;
  return actions.map(a =>
    a.id === 'approve' ? { ...a, label: p.approveLabel } : a,
  );
}
